def normalize():
    codebooks = load_codebooks()
    logs = pd.read_csv('data/test_center_logs.csv')

    # Pre-process codebooks for faster lookup
    processed_codebooks = {}
    for pid, cb in codebooks.items():
        cb_list = []
        for _, row in cb.iterrows():
            keywords = [k.strip().lower() for k in str(row['keywords_examples']).split(',')]
            stations = set(str(row['station_scope']).split(';'))
            cb_list.append({
                'code': row['code'],
                'standard_label': row['standard_label'],
                'keywords': keywords,
                'stations': stations
            })
        processed_codebooks[pid] = cb_list

    results = []
    for _, row in logs.iterrows():
        record_id = row['record_id']
        product_id = row['product_id']
        station = row['station']
        raw_text = row['raw_reason_text']

        segments = segment_text(raw_text)
        normalized_segments = []

        cb_list = processed_codebooks.get(product_id, [])

        for i, span in enumerate(segments):
            best_match = None
            max_score = -1.0
            span_lower = span.lower()

            for cb_item in cb_list:
                score = 0.0
                match_count = 0
                for k in cb_item['keywords']:
                    if k in span_lower:
                        # Simple check for word boundary if it's alphanumeric
                        if k.isalnum():
                            if re.search(r'\b' + re.escape(k) + r'\b', span_lower):
                                match_count += 1
                            else:
                                match_count += 0.2
                        else:
                            match_count += 1

                if match_count > 0:
                    score += 0.7 * (min(match_count, 2) / 2) + 0.1

                if station in cb_item['stations']:
                    score += 0.2
                else:
                    score -= 0.2

                if score > max_score:
                    max_score = score
                    best_match = cb_item

            if max_score >= 0.5 and best_match is not None:
                pred_code = best_match['code']
                pred_label = best_match['standard_label']
                confidence = max_score
            else:
                pred_code = "UNKNOWN"
                pred_label = ""
                confidence = min(0.4, max(0.1, max_score))

            normalized_segments.append({
                "segment_id": f"{record_id}-S{i+1}",
                "span_text": span,
                "pred_code": pred_code,
                "pred_label": pred_label,
                "confidence": round(float(confidence), 2),
                "rationale": f"Matched keywords in '{span}' with score {round(float(max_score), 2)}. Station: {station}."
            })

